`npm install @nestjs/config`

```typescript
import { Module } from '@nestjs/common';
import { ConfigModule } from '@nestjs/config';

@Module({
  imports: [
    ConfigModule.forRoot({
      isGlobal: true, // Rend ConfigService accessible partout sans réimporter
    }),
  ],
})
export class AppModule {}
```
L'option `isGlobal: true` évite d'importer `ConfigModule` dans chaque module qui a besoin des variables d'environnement.

```typescript
import { Injectable } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';

@Injectable()
export class WeatherService {
  constructor(private configService: ConfigService) {}

  getApiKey(): string {
    return this.configService.get<string>('API_KEY');
  }

  getApiUrl(): string {
    return this.configService.get<string>('WEATHER_API_URL');
  }
}
```

```typescript
import * as Joi from 'joi';

ConfigModule.forRoot({
  validationSchema: Joi.object({
    API_KEY: Joi.string().required().not.empty(),
    WEATHER_API_URL: Joi.string().uri().required(),
  }),
});
